#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int left = N * 9;   // N * 0.9 * 10
        int right = M * 10; // M * 10
        if (left < right) {
            printf("ONLINE\n");
        } else if (left > right) {
            printf("DINING\n");
        } else {
            printf("EITHER\n");
        }
    }
    return 0;
}

