#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        M = int(next(it))
        left = N * 9
        right = M * 10
        if left < right:
            out_lines.append("ONLINE")
        elif left > right:
            out_lines.append("DINING")
        else:
            out_lines.append("EITHER")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

